CREATE DATABASE IF NOT EXISTS music_archive CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE music_archive;

DROP TABLE IF EXISTS news;
DROP TABLE IF EXISTS categories;

CREATE TABLE categories (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    description TEXT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE news (
    id INT AUTO_INCREMENT PRIMARY KEY,
    header VARCHAR(255) NOT NULL,
    content TEXT NOT NULL,
    image VARCHAR(255) DEFAULT 'img/album.svg',
    datatime DATE NOT NULL,
    category_id INT NOT NULL DEFAULT 1,
    artist VARCHAR(150) DEFAULT NULL,
    release_year INT DEFAULT NULL,
    CONSTRAINT fk_news_category FOREIGN KEY (category_id) REFERENCES categories(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

