INSERT INTO news (header, content, image, datatime, category_id, artist, release_year) VALUES
('Р›РµРіРµРЅРґР°СЂРЅРёР№ Р°Р»СЊР±РѕРј Queen - A Night at the Opera', 'A Night at the Opera РІРІР°Р¶Р°СЋС‚СЊ РѕРґРЅРёРј С–Р· РЅР°Р№РІР°Р¶Р»РёРІС–С€РёС… СЂРѕРє-Р°Р»СЊР±РѕРјС–РІ 1970-С… СЂРѕРєС–РІ. РџР»Р°С‚С–РІРєР° РїРѕС”РґРЅР°Р»Р° Р°СЂС‚-СЂРѕРє, С…Р°СЂРґ-СЂРѕРє, РїРѕРї-РјСѓР·РёРєСѓ С‚Р° РµР»РµРјРµРЅС‚Рё РѕРїРµСЂРё. РЎР°РјРµ С‚СѓС‚ Р±СѓР»Р° РїСЂРµРґСЃС‚Р°РІР»РµРЅР° РєРѕРјРїРѕР·РёС†С–СЏ Bohemian Rhapsody, СЏРєР° СЃС‚Р°Р»Р° РїСЂРёРєР»Р°РґРѕРј СЃРјС–Р»РёРІРѕРіРѕ СЃС‚СѓРґС–Р№РЅРѕРіРѕ РµРєСЃРїРµСЂРёРјРµРЅС‚Сѓ С‚Р° Р·РјС–РЅРёР»Р° СѓСЏРІР»РµРЅРЅСЏ РїСЂРѕ С„РѕСЂРјР°С‚ СЂРѕРє-СЃРёРЅРіР»Сѓ.', 'img/queen_night_opera.svg', '2026-04-20', 1, 'Queen', 1975),
('РЎРєСЂСЏР±С–РЅ СЏРє СЏРІРёС‰Рµ СѓРєСЂР°С—РЅСЃСЊРєРѕС— РјСѓР·РёС‡РЅРѕС— СЃС†РµРЅРё', 'Р“СѓСЂС‚ РЎРєСЂСЏР±С–РЅ РїСЂРѕР№С€РѕРІ С€Р»СЏС… РІС–Рґ РµР»РµРєС‚СЂРѕРЅРЅРѕС— Р°Р»СЊС‚РµСЂРЅР°С‚РёРІРё РґРѕ Р·СЂРѕР·СѓРјС–Р»РѕРіРѕ С€РёСЂРѕРєС–Р№ Р°СѓРґРёС‚РѕСЂС–С— РїРѕРї-СЂРѕРєСѓ. РџС–СЃРЅС– РђРЅРґСЂС–СЏ РљСѓР·СЊРјРµРЅРєР° РїРѕС”РґРЅСѓСЋС‚СЊ С–СЂРѕРЅС–СЋ, РїСЂРѕСЃС‚Сѓ РјРѕРІСѓ, СЃРѕС†С–Р°Р»СЊРЅС– С‚РµРјРё С‚Р° С‰РёСЂС– РѕСЃРѕР±РёСЃС‚С– С–СЃС‚РѕСЂС–С—. РЈ РјСѓР·РёС‡РЅРѕРјСѓ Р°СЂС…С–РІС– С‚Р°РєС– Р·Р°РїРёСЃРё РґРѕРїРѕРјР°РіР°СЋС‚СЊ РїСЂРѕСЃС‚РµР¶РёС‚Рё СЂРѕР·РІРёС‚РѕРє СѓРєСЂР°С—РЅСЃСЊРєРѕС— РїРѕРїСѓР»СЏСЂРЅРѕС— РјСѓР·РёРєРё.', 'img/skriabin_kuzma.svg', '2026-04-21', 2, 'РЎРєСЂСЏР±С–РЅ', 1989),
('Р”Р¶Р°Р·: С–РјРїСЂРѕРІС–Р·Р°С†С–СЏ СЏРє РѕСЃРЅРѕРІР° Р¶Р°РЅСЂСѓ', 'Р”Р¶Р°Р· РІРёРЅРёРє РЅР° РјРµР¶С– XIX-XX СЃС‚РѕР»С–С‚СЊ С– СЃС‚Р°РІ РѕРґРЅРёРј С–Р· РЅР°Р№РІРїР»РёРІРѕРІС–С€РёС… РјСѓР·РёС‡РЅРёС… РЅР°РїСЂСЏРјС–РІ. Р™РѕРіРѕ РіРѕР»РѕРІРЅРёРјРё РѕР·РЅР°РєР°РјРё С” С–РјРїСЂРѕРІС–Р·Р°С†С–СЏ, СЃРёРЅРєРѕРїРѕРІР°РЅРёР№ СЂРёС‚Рј, СЃРєР»Р°РґРЅР° РіР°СЂРјРѕРЅС–СЏ С‚Р° С–РЅРґРёРІС–РґСѓР°Р»СЊРЅР° РјР°РЅРµСЂР° РІРёРєРѕРЅР°РЅРЅСЏ. РђСЂС…С–РІСѓРІР°РЅРЅСЏ РґР¶Р°Р·РѕРІРёС… Р·Р°РїРёСЃС–РІ РІР°Р¶Р»РёРІРµ РґР»СЏ Р·Р±РµСЂРµР¶РµРЅРЅСЏ СѓРЅС–РєР°Р»СЊРЅРёС… РєРѕРЅС†РµСЂС‚РЅРёС… РІРµСЂСЃС–Р№ С‚РІРѕСЂС–РІ.', 'img/jazz_improvisation.svg', '2026-04-22', 3, 'Р С–Р·РЅС– РІРёРєРѕРЅР°РІС†С–', 1900),
('Р’С–РЅС–Р»РѕРІС– РїР»Р°С‚С–РІРєРё С‚Р° РєСѓР»СЊС‚СѓСЂР° СЃР»СѓС…Р°РЅРЅСЏ РјСѓР·РёРєРё', 'Р’С–РЅС–Р»РѕРІС– РїР»Р°С‚С–РІРєРё Р±СѓР»Рё РѕСЃРЅРѕРІРЅРёРј РЅРѕСЃС–С”Рј РјСѓР·РёРєРё Сѓ РґСЂСѓРіС–Р№ РїРѕР»РѕРІРёРЅС– XX СЃС‚РѕР»С–С‚С‚СЏ. Р’РѕРЅРё СЃС„РѕСЂРјСѓРІР°Р»Рё РѕСЃРѕР±Р»РёРІСѓ РєСѓР»СЊС‚СѓСЂСѓ РїСЂРѕСЃР»СѓС…РѕРІСѓРІР°РЅРЅСЏ: РІС–Рґ СѓРІР°Р¶РЅРѕРіРѕ РІРёР±РѕСЂСѓ РїР»Р°С‚С–РІРєРё РґРѕ РѕС„РѕСЂРјР»РµРЅРЅСЏ РѕР±РєР»Р°РґРёРЅРєРё С‚Р° РєРѕР»РµРєС†С–РѕРЅСѓРІР°РЅРЅСЏ. РЎСЊРѕРіРѕРґРЅС– РІС–РЅС–Р» Р·РЅРѕРІСѓ РїРѕРїСѓР»СЏСЂРЅРёР№ СЃРµСЂРµРґ РјРµР»РѕРјР°РЅС–РІ Р·Р°РІРґСЏРєРё С„С–Р·РёС‡РЅРѕРјСѓ С„РѕСЂРјР°С‚Сѓ С– С…Р°СЂР°РєС‚РµСЂРЅРѕРјСѓ Р·РІСѓС‡Р°РЅРЅСЋ.', 'img/vinyl_records.svg', '2026-04-23', 4, 'РђСЂС…С–РІРЅРёР№ РјР°С‚РµСЂС–Р°Р»', 1948),
('Pink Floyd - The Dark Side of the Moon', 'The Dark Side of the Moon С” РєРѕРЅС†РµРїС‚СѓР°Р»СЊРЅРёРј Р°Р»СЊР±РѕРјРѕРј, Сѓ СЏРєРѕРјСѓ СЂРѕР·РєСЂРёРІР°СЋС‚СЊСЃСЏ С‚РµРјРё С‡Р°СЃСѓ, СЃС‚СЂР°С…Сѓ, РіСЂРѕС€РµР№ С– Р»СЋРґСЃСЊРєРѕРіРѕ Р¶РёС‚С‚СЏ. РџР»Р°С‚С–РІРєР° СЃС‚Р°Р»Р° РєР»Р°СЃРёС‡РЅРёРј РїСЂРёРєР»Р°РґРѕРј РїСЂРѕРіСЂРµСЃРёРІРЅРѕРіРѕ СЂРѕРєСѓ С‚Р° СЃС‚СѓРґС–Р№РЅРѕС— СЂРѕР±РѕС‚Рё Р·С– Р·РІСѓРєРѕРј. Р‡С— С‡Р°СЃС‚Рѕ РІРєР»СЋС‡Р°СЋС‚СЊ РґРѕ РїРµСЂРµР»С–РєС–РІ РЅР°Р№РІРїР»РёРІРѕРІС–С€РёС… Р°Р»СЊР±РѕРјС–РІ РІ С–СЃС‚РѕСЂС–С— РјСѓР·РёРєРё.', 'img/pink_floyd_1971.svg', '2026-04-24', 1, 'Pink Floyd', 1973),
('Р•Р»РµРєС‚СЂРѕРЅРЅР° РјСѓР·РёРєР°: РІС–Рґ СЃРёРЅС‚РµР·Р°С‚РѕСЂС–РІ РґРѕ С†РёС„СЂРѕРІРёС… СЃС‚СѓРґС–Р№', 'Р•Р»РµРєС‚СЂРѕРЅРЅР° РјСѓР·РёРєР° СЂРѕР·РІРёРІР°Р»Р°СЃСЏ СЂР°Р·РѕРј С–Р· С‚РµС…РЅРѕР»РѕРіС–СЏРјРё Р·РІСѓРєРѕР·Р°РїРёСЃСѓ. РЎРёРЅС‚РµР·Р°С‚РѕСЂРё, РґСЂР°Рј-РјР°С€РёРЅРё С‚Р° С†РёС„СЂРѕРІС– СЂРѕР±РѕС‡С– СЃС‚Р°РЅС†С–С— Р·РјС–РЅРёР»Рё РїСЂРѕС†РµСЃ СЃС‚РІРѕСЂРµРЅРЅСЏ РєРѕРјРїРѕР·РёС†С–Р№. РЈ РјСѓР·РёС‡РЅРѕРјСѓ Р°СЂС…С–РІС– С†РµР№ Р¶Р°РЅСЂ РІР°Р¶Р»РёРІРѕ РѕРїРёСЃСѓРІР°С‚Рё С‡РµСЂРµР· С–РЅСЃС‚СЂСѓРјРµРЅС‚Рё, РїСЂРѕРіСЂР°РјРЅРµ Р·Р°Р±РµР·РїРµС‡РµРЅРЅСЏ С‚Р° РєСѓР»СЊС‚СѓСЂРЅРёР№ РєРѕРЅС‚РµРєСЃС‚.', 'img/electronic_studio.svg', '2026-04-25', 3, 'Р С–Р·РЅС– РІРёРєРѕРЅР°РІС†С–', 1970);

